-- 1. Garden Services x Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'garden-services',
  'web-design',
  'Garden service businesses operate across a spectrum from weekly lawn mowing rounds to full garden maintenance packages including hedge trimming, border work, leaf clearance, and seasonal planting. Your website needs to communicate this range while making it effortless for homeowners to book the specific services they need. Unlike one-off project trades, garden maintenance is a recurring relationship business. Your website must convert first-time visitors into regular customers by clearly presenting your service packages, pricing structure, and the areas you cover. It needs to showcase the difference between a neglected garden and one maintained by your team through seasonal photography showing spring lawn treatments, summer border displays, autumn clearances, and winter pruning results. Most garden service websites are basic one-page affairs with a phone number and a vague list of services. We build garden maintenance websites that let homeowners select their garden size, choose from clearly defined service packages, see indicative pricing, and book their first visit online, converting browsing homeowners into recurring monthly clients without a single phone call.',
  'Homeowners searching for garden maintenance want to know three things immediately: do you cover their area, what services do you offer, and roughly how much will it cost. A website that fails to answer these questions forces them to phone, and most will not bother. They will book with the competitor whose website provides clear service packages, transparent pricing, and an online booking option. For a recurring revenue business like garden maintenance, every lost website visitor represents months or years of ongoing revenue.',
  'We design garden service websites around the recurring booking model. Service package pages clearly outline what is included in weekly, fortnightly, and monthly maintenance visits. An interactive garden size estimator provides indicative pricing. Online booking captures garden details, access information, and preferred visit frequency. Seasonal galleries show your work across all four seasons.',
  '[{"title": "No clear service packages or pricing guidance", "description": "Homeowners considering regular garden maintenance want to understand what they will receive and approximately how much it will cost before making contact. A website listing lawn mowing, hedge trimming, and weeding without explaining how these combine into maintenance packages or providing any pricing indication loses visitors to competitors who present structured, transparent offerings."}, {"title": "No online booking for the modern homeowner", "description": "Busy professionals who want a gardener do not want to play phone tag. They research garden services in the evening, compare options, and want to book online. Without an online booking system that captures their garden size, required services, access details, and preferred schedule, you miss the growing segment of homeowners who expect to arrange services digitally."}, {"title": "No seasonal showcase demonstrating year-round capability", "description": "Garden maintenance is a year-round service, but most garden company websites show only summer photos. Without seasonal galleries demonstrating spring lawn treatments, summer border management, autumn leaf clearance, and winter pruning, homeowners assume your service is limited to grass cutting and do not consider you for the comprehensive maintenance package they actually need."}]',
  '[{"title": "Service package pages with clear inclusions and pricing", "description": "Structured pages presenting your maintenance packages: what is included in a basic lawn care visit versus a comprehensive garden maintenance package, how often each service is performed, and what seasonal work is covered. Indicative pricing based on garden size gives homeowners the cost transparency they need to make a decision. Each package page is designed to convert browsers into booking enquiries."}, {"title": "Online booking system with garden detail capture", "description": "A step-by-step booking form that captures garden size using a simple small, medium, or large selector with visual examples, required services, access arrangements including side gate codes and key safe details, preferred visit day and frequency, and any specific requirements. Homeowners book their first maintenance visit without a phone call, and you receive a complete brief before arriving."}, {"title": "Four-season portfolio showcasing year-round maintenance", "description": "Galleries organised by season showing the breadth of your maintenance work: spring lawn scarification and overseeding results, summer border planting and hedge shaping, autumn leaf clearance and garden tidying, and winter structural pruning and hard landscaping maintenance. This positions your business as a year-round garden partner rather than just a grass-cutting service."}]',
  '[{"question": "Should I show my pricing on the website?", "answer": "For garden maintenance services, indicative pricing significantly increases conversion rates. Homeowners expect transparency from recurring service providers. We recommend showing starting-from prices based on garden size categories rather than fixed quotes. This pre-qualifies visitors and ensures enquiries come from homeowners whose budget aligns with your rates."}, {"question": "Can the website handle recurring booking management?", "answer": "The booking system captures initial visit details and preferred schedule. For ongoing management, we integrate with scheduling tools that handle recurring appointments, route planning, and customer communication. The website serves as the entry point that converts new customers, while your operational systems manage the ongoing relationship."}, {"question": "How do I showcase seasonal work when I only have photos from summer?", "answer": "We start with your existing photography and build the seasonal gallery progressively. We provide a simple photo capture guide so your team photographs key seasonal work throughout the year: scarification in spring, hedge trimming in summer, leaf clearance in autumn, and pruning in winter. Within twelve months you have a comprehensive seasonal portfolio."}, {"question": "How long does a garden services website take to build?", "answer": "Most garden service websites launch within three to four weeks. The service package structure and booking system are prioritised for early launch. Seasonal galleries build over time as you capture work across different seasons. We launch with your strongest current photography and add seasonal content as it becomes available."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Garden Services x SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'garden-services',
  'seo',
  'When a homeowner searches for gardener near me or garden maintenance services in their local town, the results they see determine which companies receive their enquiry. For garden service businesses, SEO is particularly valuable because each new organic enquiry represents not a one-off job but potentially years of recurring monthly revenue. A single first-page ranking for lawn care services Maidstone could generate dozens of new regular customers annually, each worth hundreds of pounds per year in ongoing maintenance fees. The challenge is that garden services is a fragmented market where dozens of sole traders and small businesses compete locally, while national franchise operations like Fantastic Services and GreenThumb target the same keywords with substantial marketing budgets. Our SEO campaigns for garden maintenance companies target the full range of services homeowners search for: regular garden maintenance, lawn care and treatment, hedge trimming, seasonal clearances, and one-off garden tidying. Every keyword is mapped to location-specific pages covering the towns and villages where you operate, building a web of local relevance that Google rewards with consistent search visibility.',
  'Garden maintenance customers have high lifetime value. A homeowner who books a fortnightly maintenance visit at eighty pounds per visit represents nearly two thousand pounds in annual revenue, and the average garden maintenance customer stays for three to five years. Every first-page ranking position that generates a new recurring customer compounds in value over time. SEO is the highest-return marketing investment for any garden maintenance business because each lead generates ongoing revenue rather than a single project fee.',
  'Garden service SEO requires seasonal keyword planning because search demand shifts dramatically through the year. Lawn care searches peak in spring, hedge trimming in summer, leaf clearance in autumn, and garden tidying before Christmas. We build content and optimisation calendars aligned to these seasonal patterns, ensuring your pages rank in time for each demand surge rather than trailing behind.',
  '[{"title": "Invisible for garden maintenance searches in your service area", "description": "Homeowners searching for gardener near me, lawn mowing service, or garden maintenance in their specific town will contact the companies they find on the first page of results. If your website does not appear for these searches in every town you serve, potential long-term customers, each worth thousands in lifetime revenue, are booking with competitors who invested in local search visibility."}, {"title": "National franchise brands outranking local garden services", "description": "GreenThumb, Fantastic Services, and other national operators invest heavily in SEO to dominate garden service search results. These brands often charge premium prices and deliver impersonal service, yet they appear above local independents who provide better value and more personalised care. Without SEO investment, your website cannot compete with these corporate marketing budgets."}, {"title": "No seasonal content capturing cyclical search demand", "description": "Garden service searches follow strong seasonal patterns: lawn care peaks in March and April, hedge trimming in June and July, leaf clearance in October and November, and garden tidying before Christmas. Without content targeting these seasonal terms in advance, your website misses the surges in demand that drive new customer acquisition at the most opportune times of year."}]',
  '[{"title": "Service-specific pages targeting garden maintenance search terms", "description": "Dedicated, optimised pages for every service you offer: regular garden maintenance, lawn mowing and treatment, hedge trimming and reduction, border maintenance and seasonal planting, leaf and garden clearance, tree and shrub pruning, and one-off garden tidying. Each page targets the specific terms homeowners search for and includes your seasonal scheduling, service area, and indicative pricing to convert visitors into enquiries."}, {"title": "Location pages covering every town in your maintenance rounds", "description": "Individual pages for every town and village in your service area, each featuring the specific services available in that location and any completed project references. Garden maintenance Tonbridge, lawn care Sevenoaks, hedge trimming Maidstone: each combination captures local searches and builds your reputation as the established garden service provider in that area."}, {"title": "Seasonal content calendar aligned to search demand peaks", "description": "We plan and publish content months ahead of seasonal demand surges. Lawn care content is optimised and ranking by February for March search peaks. Hedge trimming content peaks in May for June demand. Autumn clearance pages are ready by September. This proactive approach ensures your website captures seasonal traffic when it matters most for new customer acquisition."}]',
  '[{"question": "How valuable is a single garden maintenance SEO lead?", "answer": "Extremely valuable because of recurring revenue. A homeowner who finds you through a Google search for gardener near me and books fortnightly maintenance at eighty to one hundred pounds per visit represents nearly two thousand pounds in first-year revenue and potentially eight to ten thousand pounds over a typical customer lifetime. Even a modest number of monthly organic leads translates to significant compounding revenue."}, {"question": "How long before SEO generates new garden maintenance customers?", "answer": "Most garden services see ranking improvements for specific town-plus-service terms within eight to twelve weeks. Terms like garden maintenance Faversham or lawn mowing Whitstable are typically less competitive than broader terms and deliver results faster. We focus on your core service area towns first to generate early results while building authority for more competitive broader terms."}, {"question": "Should I target lawn care and garden maintenance separately?", "answer": "Yes. Homeowners searching for lawn care and those searching for garden maintenance have different needs and intent. Lawn care searchers may want treatment services like scarification, overseeding, and fertilisation. Garden maintenance searchers typically want comprehensive ongoing care. Separate content strategies for each capture both audiences and their distinct service requirements."}, {"question": "How does seasonal SEO work for a garden services business?", "answer": "We plan content around the predictable seasonal search patterns. Lawn care and spring garden content is published in January and February to rank before March demand peaks. Summer hedge and border content is ready by April. Autumn clearance content publishes in August. This lead time ensures your pages are ranking when homeowners start searching for each seasonal service."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
