-- 3. Garden Services x Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'garden-services',
  'lead-capture',
  'Garden maintenance businesses have a unique lead capture advantage: every new customer represents recurring monthly revenue rather than a one-off project. This makes lead capture systems extraordinarily valuable because converting a single website visitor into a regular maintenance customer generates revenue that compounds over years. Yet most garden service websites offer nothing more than a phone number and a generic contact form. A homeowner browsing at nine in the evening, comparing garden maintenance companies, has no way to get an indicative price, understand what is included in your service packages, or book a consultation visit. Purpose-built lead capture for garden services guides homeowners through a garden assessment that captures their property size, current garden condition, required services, preferred visit frequency, and access arrangements. An indicative price calculator based on garden size and service level converts browsing into commitment. For one-off services like clearances and autumn tidying, separate lead paths capture the specific scope and timeline. Every enquiry arrives with the detail needed to schedule efficiently and quote accurately.',
  'Garden maintenance customers typically research several providers before choosing one. The decision is significant because they are committing to a recurring expense and regular access to their property. Without lead capture that provides immediate value through pricing guidance and service clarity, you rely on phone calls to convert interest into bookings. Most homeowners will not call three gardeners to compare. They will engage with the one whose website answers their questions and captures their requirements automatically.',
  'We build lead capture around the recurring service model. Maintenance enquiry forms capture garden size, condition, required services, and preferred frequency, then calculate indicative pricing. One-off service forms for clearances and tidying capture scope and photos. Seasonal prompt campaigns re-engage previous enquirers who did not convert, targeting the specific service period they originally searched for.',
  '[{"title": "Evening browsers leaving without any engagement", "description": "Most homeowners research garden services in the evening when they are not working. Without an interactive tool that provides immediate value, such as a garden maintenance price estimator or a service package comparison tool, these evening visitors compare your basic website against a competitor who provides instant pricing and online booking, and choose the path of least resistance."}, {"title": "No differentiation between maintenance and one-off service enquiries", "description": "A homeowner wanting ongoing weekly maintenance and someone needing a one-off garden clearance have completely different needs. A generic contact form treats both identically, capturing insufficient detail for either. The maintenance prospect needs to specify garden size and service frequency. The clearance customer needs to describe the scope and timeline. Without separate paths, both are underserved."}, {"title": "No system to re-engage enquiries that did not convert", "description": "A homeowner who enquired about garden maintenance in March but did not book may have been put off by the initial commitment or wanted to wait for better weather. Without a system to re-engage these warm leads when the season changes or when they are most likely to reconsider, this earlier interest is wasted entirely."}]',
  '[{"title": "Garden maintenance price estimator with service package selection", "description": "An interactive calculator where homeowners select their garden size from visual examples, choose their preferred service level from basic lawn care to comprehensive maintenance, indicate their preferred visit frequency, and receive an indicative monthly cost. This transparent pricing builds trust and converts browsers into enquiries with realistic budget expectations already set."}, {"title": "Separate lead paths for maintenance and one-off services", "description": "Maintenance enquiries capture garden size, current condition with optional photos, required services, preferred visit day and frequency, and access arrangements. One-off service enquiries for clearances, hedge reductions, and seasonal tidying capture the specific scope, urgency, and any access or waste removal considerations. Each path provides the information your team needs to schedule and price efficiently."}, {"title": "Seasonal re-engagement campaigns for unconverted leads", "description": "Homeowners who enquired but did not book receive targeted emails aligned to seasonal service periods. A spring email highlights lawn revival services. A summer email promotes hedge trimming and border maintenance. An autumn email offers garden clearance packages. These seasonal touchpoints re-engage prospects at the moment they are most likely to recognise the need for your services."}]',
  '[{"question": "How does the garden maintenance price estimator work?", "answer": "Homeowners select their garden size from visual categories showing typical small, medium, and large gardens. They choose their service level: basic lawn care only, standard maintenance including hedges and borders, or comprehensive care including seasonal planting and treatment. They select their preferred visit frequency. The estimator provides an indicative monthly cost based on your actual pricing structure while capturing their contact details and garden information."}, {"question": "Can lead capture help convert one-off customers into regular maintenance clients?", "answer": "Yes. When a homeowner books a one-off clearance or tidy-up, the system sends a follow-up sequence after the work is completed, offering a discounted first month of regular maintenance. This converts customers who have already experienced your quality into recurring clients, which is significantly easier than acquiring entirely new maintenance customers."}, {"question": "What information should a maintenance enquiry form capture?", "answer": "Garden size and type, current condition, required services such as lawn care, hedges, borders, and seasonal work, preferred visit frequency and day of week, access arrangements including gate codes or key safes, any specific requirements like pet safety or areas to avoid, and preferred contact method. This detail allows you to assess the enquiry, route plan efficiently, and provide an accurate quote."}, {"question": "How effective are seasonal re-engagement emails?", "answer": "Highly effective because they reach homeowners at the exact moment the need for your specific service is most apparent. A March email about spring lawn revival arrives when homeowners are looking at their patchy, moss-covered grass. An October email about leaf clearance arrives when gutters are blocking and lawns are disappearing under fallen leaves. This timing converts previous interest into current bookings."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
