-- 5. Garden Services x Branding
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'garden-services',
  'branding',
  'Garden service businesses visit the same residential streets week after week, with branded vehicles, uniformed teams, and equipment trailers visible to every neighbour for the duration of each visit. This repeated local visibility makes branding exceptionally powerful for garden maintenance companies. Your van parked outside a well-maintained garden is an endorsement of your work that every passing homeowner sees. Your team trimming hedges or mowing lawns in branded workwear signals a professional operation to everyone on the street. A garden gate sign reading Maintained by Your Company Name turns every customer''s garden into a permanent advertisement. Professional branding for garden services creates a visual identity system that maximises this inherent visibility: vehicle graphics that communicate garden care professionalism, crew uniforms that look smart while being practical for physical outdoor work, customer garden signs that generate neighbour enquiries, and printed materials including seasonal service flyers and maintenance tips cards that keep your name on the kitchen noticeboard. For a business that operates in public view every working day, branding investment pays for itself through the sheer volume of impressions it generates.',
  'Garden maintenance is one of the most visible recurring trades. Unlike a plumber who visits once, your team appears on residential streets weekly or fortnightly for years. Every visit is seen by neighbours, dog walkers, and passing drivers. Unbranded teams in random clothing look like casual labourers, which undermines homeowner confidence and fails to generate the neighbour referrals that drive garden service growth. Professional branding transforms your routine visibility into a continuous marketing presence.',
  'We design garden service brands for maximum outdoor visibility and durability. Vehicle graphics use nature-inspired colour palettes with bold, readable company names. Crew workwear is designed for comfort during physical garden work while maintaining a smart, professional appearance. Customer garden signs are weather-resistant and designed with subtle branding that homeowners are happy to display.',
  '[{"title": "Vehicles and crews generating zero brand awareness despite weekly visibility", "description": "Your van and team are visible on residential streets five or six days per week, yet if they carry no branding, this enormous marketing opportunity is completely wasted. A plain van and unbranded crew maintaining a beautiful garden generate no recognition, no enquiries, and no competitive advantage. Neighbours who might enquire have no idea who is responsible for the excellent work they see weekly."}, {"title": "No customer garden signs converting neighbour interest into enquiries", "description": "Every garden you maintain is a living advertisement for your services. Neighbours walking past a beautifully maintained garden notice and admire the work, but without a subtle branded sign at the garden boundary, they have no way to identify or contact your company. This simple branding touchpoint converts passive admiration into active enquiries more effectively than any digital marketing."}, {"title": "Crew appearance undermining the quality of garden work", "description": "A beautifully maintained garden paired with a scruffy crew in mismatched clothing creates a contradictory impression. The homeowner whose garden you maintain and the neighbours who observe your team both form judgements based on appearance. Branded, smart workwear that is practical for mowing, hedging, and planting reinforces the quality and professionalism of your garden maintenance."}]',
  '[{"title": "Vehicle branding designed for residential street impact", "description": "Van and trailer graphics using fresh, nature-inspired colour palettes with your company name in bold, readable typography. Vehicle graphics are designed for visibility at street-parking distance, featuring your service types and phone number. For businesses with multiple vehicles, consistent fleet branding creates the impression of an established, scaled operation that homeowners trust with ongoing garden care."}, {"title": "Customer garden signs generating passive referrals", "description": "Discrete, weather-resistant signs designed for garden gate posts or border edges reading Maintained by Your Company Name with your phone number or website. These signs are offered free to customers and generate a steady stream of neighbour enquiries from homeowners who see the quality of your maintenance and want the same for their garden. Each sign is a permanent, zero-cost lead generation tool."}, {"title": "Practical branded workwear for outdoor garden work", "description": "Branded polo shirts, softshell jackets, and waterproof layers designed for the physical demands of garden maintenance: comfortable during mowing and hedge trimming, breathable during summer work, and waterproof for the days you work through drizzle. Embroidered branding withstands daily wear, mud, and grass staining while maintaining a professional appearance that customers and neighbours notice."}]',
  '[{"question": "How effective are garden maintenance customer signs for generating referrals?", "answer": "Extremely effective. Garden service businesses consistently report that customer garden signs are their single most cost-effective marketing tool. A well-maintained garden with a branded sign is seen by neighbours daily, and the quality of your work does the selling. Many garden services attribute thirty to fifty percent of their new customer enquiries to neighbours seeing their signs and calling directly."}, {"question": "What kind of workwear is practical for garden maintenance crews?", "answer": "We supply branded polo shirts in breathable fabrics for summer, softshell jackets for spring and autumn, and waterproof layers for wet weather work. All items are embroidered rather than printed, ensuring branding survives repeated washing. Colours are chosen to look professional on residential streets while being practical for the inevitable grass stains, mud, and hedge clippings of daily garden work."}, {"question": "Can you brand equipment trailers as well as vans?", "answer": "Yes. For garden services with equipment trailers, branded graphics on trailer sides represent significant additional advertising as the trailer is visible from both sides when parked on residential streets. Trailer branding typically includes your company name, phone number, website, and a visual element that communicates professional garden care. The trailer becomes a large advertising board positioned on your customers'' streets."}, {"question": "How do I convince customers to display a garden sign?", "answer": "Most customers are happy to display a small, tasteful sign acknowledging your work, especially when framed as a compliment to their garden. We design signs that are attractive enough that homeowners see them as an enhancement rather than an advertisement. Offering a modest discount or a free seasonal treatment in exchange for sign placement increases uptake further."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
